import{_ as t,c as o,o as s,ae as a}from"./chunks/framework.CDjunVez.js";const u=JSON.parse('{"title":"Logs & Log Management","description":"","frontmatter":{},"headers":[],"relativePath":"website/log.md","filePath":"website/log.md"}'),r={name:"website/log.md"};function i(n,e,l,d,g,c){return s(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="logs-log-management" tabindex="-1">Logs &amp; Log Management <a class="header-anchor" href="#logs-log-management" aria-label="Permalink to &quot;Logs &amp; Log Management&quot;">​</a></h1><p>KiwiPanel collects logs from the panel itself, third-party services, website traffic, and terminal sessions. All logs are accessible from the admin dashboard — no SSH required.</p><h2 id="system-logs" tabindex="-1">System Logs <a class="header-anchor" href="#system-logs" aria-label="Permalink to &quot;System Logs&quot;">​</a></h2><p>Navigate to <strong>Dashboard → System Logs</strong> to view logs from all system components. Each log type has its own tab.</p><h3 id="available-logs" tabindex="-1">Available Logs <a class="header-anchor" href="#available-logs" aria-label="Permalink to &quot;Available Logs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Log</th><th>What it contains</th></tr></thead><tbody><tr><td><strong>Panel</strong></td><td>KiwiPanel application logs (startup, errors, requests)</td></tr><tr><td><strong>Agent</strong></td><td>Agent service logs (system operations, terminal sessions)</td></tr><tr><td><strong>Install</strong></td><td>Installation script output</td></tr><tr><td><strong>Update</strong></td><td>Self-update process logs</td></tr><tr><td><strong>Security</strong></td><td>Authentication attempts, rate limiting events</td></tr><tr><td><strong>OpenLiteSpeed</strong></td><td>Web server error log</td></tr><tr><td><strong>MariaDB</strong></td><td>Database server error log</td></tr></tbody></table><p>Each tab supports filtering by the number of lines (default: 100) and includes a search box to find specific entries.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Panel and Agent logs come from systemd journal on production servers. Install, Update, and Security logs are stored as plain text files with automatic rotation.</p></div><h2 id="website-logs" tabindex="-1">Website Logs <a class="header-anchor" href="#website-logs" aria-label="Permalink to &quot;Website Logs&quot;">​</a></h2><p>Each website has a dedicated <strong>Logs</strong> page showing traffic and error data from three sources.</p><h3 id="viewing-website-logs" tabindex="-1">Viewing Website Logs <a class="header-anchor" href="#viewing-website-logs" aria-label="Permalink to &quot;Viewing Website Logs&quot;">​</a></h3><ol><li>Go to <strong>Websites</strong> in the sidebar</li><li>Click on a website to open its detail page</li><li>Select the <strong>Logs</strong> tab</li></ol><p>You&#39;ll see three sub-tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>What it shows</th></tr></thead><tbody><tr><td><strong>Access Logs</strong></td><td>Incoming HTTP requests — IP address, URL, status code, response size, user agent</td></tr><tr><td><strong>Error Logs</strong></td><td>Web server errors — timestamps, severity level, error messages</td></tr><tr><td><strong>PHP Logs</strong></td><td>PHP errors and warnings — fatal errors, notices, stack traces, <code>error_log()</code> output</td></tr></tbody></table><h3 id="summary-stats" tabindex="-1">Summary Stats <a class="header-anchor" href="#summary-stats" aria-label="Permalink to &quot;Summary Stats&quot;">​</a></h3><p>At the top of the logs page, summary cards show:</p><ul><li><strong>Total Requests</strong> — number of logged access entries</li><li><strong>Error Rate</strong> — percentage of 4xx and 5xx responses</li><li><strong>Bandwidth Used</strong> — total response size across all entries</li></ul><h3 id="adjusting-the-number-of-lines" tabindex="-1">Adjusting the Number of Lines <a class="header-anchor" href="#adjusting-the-number-of-lines" aria-label="Permalink to &quot;Adjusting the Number of Lines&quot;">​</a></h3><p>Use the <strong>Lines</strong> dropdown to show the last 200, 500, or 1,000 log entries. Logs are always read from the end of the file, so you&#39;re seeing the most recent entries first.</p><h3 id="clearing-logs" tabindex="-1">Clearing Logs <a class="header-anchor" href="#clearing-logs" aria-label="Permalink to &quot;Clearing Logs&quot;">​</a></h3><p>Click the <strong>Clear Logs</strong> dropdown to truncate log files:</p><ul><li><strong>Clear Access Log</strong> — empties <code>access.log</code></li><li><strong>Clear Error Log</strong> — empties <code>error.log</code></li><li><strong>Clear PHP Log</strong> — empties <code>php_error.log</code></li><li><strong>Clear All Logs</strong> — empties all three</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Clearing logs is permanent and cannot be undone. The web server continues writing to the same files, so new entries will appear immediately after clearing.</p></div><div class="info custom-block"><p class="custom-block-title">Demo Mode</p><p>The Clear Logs button is hidden for demo users.</p></div><h2 id="terminal-session-logs" tabindex="-1">Terminal Session Logs <a class="header-anchor" href="#terminal-session-logs" aria-label="Permalink to &quot;Terminal Session Logs&quot;">​</a></h2><p>KiwiPanel records terminal sessions for audit and security purposes. Every global and website terminal session is logged automatically.</p><h3 id="what-gets-logged" tabindex="-1">What Gets Logged <a class="header-anchor" href="#what-gets-logged" aria-label="Permalink to &quot;What Gets Logged&quot;">​</a></h3><ul><li><strong>Session metadata</strong> — who connected, from which IP, when, and for how long</li><li><strong>Commands</strong> — every command entered during the session</li><li><strong>Session lifecycle</strong> — start time, end time, disconnect reason</li></ul><h3 id="viewing-terminal-sessions" tabindex="-1">Viewing Terminal Sessions <a class="header-anchor" href="#viewing-terminal-sessions" aria-label="Permalink to &quot;Viewing Terminal Sessions&quot;">​</a></h3><ol><li>Go to <strong>Dashboard → System Logs</strong></li><li>Select the <strong>Terminal Sessions</strong> tab</li></ol><p>You&#39;ll see a list of sessions with:</p><ul><li>Terminal type (Global or Website)</li><li>Connected user and IP address</li><li>Start time and duration</li><li>Number of commands executed</li></ul><p>Click on a session to expand it and view the full command history.</p><h3 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h3><p>Use the filters to narrow down sessions:</p><ul><li><strong>Type</strong> — show only Global or Website terminal sessions</li><li><strong>Limit</strong> — number of sessions to display</li></ul><h2 id="log-rotation" tabindex="-1">Log Rotation <a class="header-anchor" href="#log-rotation" aria-label="Permalink to &quot;Log Rotation&quot;">​</a></h2><p>KiwiPanel automatically rotates logs to prevent disk exhaustion.</p><h3 id="website-log-rotation" tabindex="-1">Website Log Rotation <a class="header-anchor" href="#website-log-rotation" aria-label="Permalink to &quot;Website Log Rotation&quot;">​</a></h3><p>Each website gets its own logrotate configuration, created automatically during website setup:</p><ul><li><strong>Frequency:</strong> Daily</li><li><strong>Retention:</strong> 14 days of history</li><li><strong>Compression:</strong> Old logs are gzip-compressed</li><li><strong>Method:</strong> In-place truncation — the web server doesn&#39;t need to be restarted</li></ul><p>When a website is deleted, its logrotate configuration is removed automatically.</p><h3 id="system-log-rotation" tabindex="-1">System Log Rotation <a class="header-anchor" href="#system-log-rotation" aria-label="Permalink to &quot;System Log Rotation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Log Type</th><th>Rotation</th><th>Retention</th></tr></thead><tbody><tr><td>Terminal sessions</td><td>Custom cleanup script</td><td>30 days active, 180 days archived</td></tr><tr><td>Security logs</td><td>Daily via logrotate</td><td>90 days</td></tr><tr><td>Update logs</td><td>Daily via logrotate</td><td>30 days</td></tr><tr><td>Install logs</td><td>Monthly via logrotate</td><td>3 months</td></tr><tr><td>Panel / Agent</td><td>journald default</td><td>14 days</td></tr></tbody></table><p>A cleanup cron job runs daily at 3 AM to archive old terminal session logs and delete expired ones. If terminal logs exceed 1 GB total, the oldest sessions are cleaned up immediately.</p><h3 id="per-website-php-error-logging" tabindex="-1">Per-Website PHP Error Logging <a class="header-anchor" href="#per-website-php-error-logging" aria-label="Permalink to &quot;Per-Website PHP Error Logging&quot;">​</a></h3><p>KiwiPanel automatically configures each website to write PHP errors to its own <code>php_error.log</code> file. This is handled transparently — you don&#39;t need to configure anything.</p><p>The following types of PHP errors are captured:</p><table tabindex="0"><thead><tr><th>Error Type</th><th>Example</th></tr></thead><tbody><tr><td>Custom logging</td><td><code>error_log(&quot;debug message&quot;)</code> output</td></tr><tr><td>Warnings</td><td>Undefined variables, deprecated functions</td></tr><tr><td>Fatal errors</td><td>Uncaught exceptions, division by zero</td></tr><tr><td>Stack traces</td><td>Full call stack for fatal errors</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>PHP error logging is managed by KiwiPanel and preserved when you change PHP settings. You don&#39;t need to set <code>error_log</code> manually in your PHP configuration.</p></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="no-logs-appearing-for-a-website" tabindex="-1">No logs appearing for a website <a class="header-anchor" href="#no-logs-appearing-for-a-website" aria-label="Permalink to &quot;No logs appearing for a website&quot;">​</a></h3><ul><li><strong>New website?</strong> Logs only appear after the site receives traffic. Visit your website in a browser to generate an access log entry.</li><li><strong>PHP logs empty?</strong> Make sure your PHP code is generating errors or using <code>error_log()</code>. Check that the PHP version is running correctly from the website&#39;s PHP settings page.</li></ul><h3 id="logs-page-loads-slowly" tabindex="-1">Logs page loads slowly <a class="header-anchor" href="#logs-page-loads-slowly" aria-label="Permalink to &quot;Logs page loads slowly&quot;">​</a></h3><p>The logs page reads the last N lines directly from log files. If you&#39;re loading 1,000 lines from a very large log file, it may take a moment. Try reducing the line count to 200.</p><h3 id="disk-space-concerns" tabindex="-1">Disk space concerns <a class="header-anchor" href="#disk-space-concerns" aria-label="Permalink to &quot;Disk space concerns&quot;">​</a></h3><p>KiwiPanel rotates website logs automatically (14-day retention). For system logs, the cleanup cron job handles terminal session archives. If you need to free space immediately, use the <strong>Clear Logs</strong> button on the website logs page or check log file sizes via the terminal.</p>',57)])])}const p=t(r,[["render",i]]);export{u as __pageData,p as default};
